 * @return std::pair<int, bool> Pair of total call count and whether chain notification worked correctly
 */
std::pair<int, bool> test_chained_observers(const std::string& targetName, 
                                            const std::string& observer1Name, 
                                            const std::string& observer2Name) {
    // 1. Create three TestChainedObserver instances with the given names
    auto target = std::make_shared<TestChainedObserver>(targetName);
    auto observer1 = std::make_shared<TestChainedObserver>(observer1Name);
    auto observer2 = std::make_shared<TestChainedObserver>(observer2Name);

    // 2. Use ObserverGraph::getInstance() to get the graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Use addNode() to add all three observers to the graph
    graph.addNode(target);
    graph.addNode(observer1);
    graph.addNode(observer2);

    // 4. Set up the chain: observer2 observes observer1, observer1 observes target
    graph.addObserver(observer2, observer1);  // observer2 depends on observer1
    graph.addObserver(observer1, target);     // observer1 depends on target

    // 5. Notify the target using valueChanged()
    target->valueChanged(true);

    // 6. Check if both observers were notified (changed flag is set)
    bool chainStatus = observer1->wasChanged() && observer2->wasChanged();

    // 7. Calculate total call count across all observers
    int totalCalls = observer1->getCallCount() + observer2->getCallCount() + target->getCallCount();

