 * @return int The result after resetting calculation to use different dependencies
 */
int test_calculation_reset(int a, int b, int c) {
    // 1. Create three reactive variables using reaction::var()
    auto var_a = reaction::var(a);
    auto var_b = reaction::var(b);
    auto var_c = reaction::var(c);

    // 2. Create initial calculation using reaction::calc() that sums all three variables
    auto initial_calc = reaction::calc([](int x, int y, int z) {
        return x + y + z;
    }, var_a, var_b, var_c);

    // 3. Use the reset() method on the calculation to change dependencies
    initial_calc.reset([](int x, int y) {
        return x + y;
    }, var_a, var_b);

    // 4. Return the result after reset
    return initial_calc();
}

}  // namespace test_reaction
