```cpp
#pragma once

#include <reaction/reaction.h>
#include <tuple>

namespace test_reaction {

// ============================================
// Function implementations
// ============================================

/**
 * Function: Test filter trigger with conditional recomputation
 *
 * @param initialValue Initial sensor value
 * @param firstUpdate First update (expected to be within threshold)
 * @param secondUpdate Second update (expected to exceed threshold)
 * @param diffThreshold Minimum delta to trigger recomputation
 * @param levelThreshold Threshold to categorize HIGH vs NORMAL
 * @return std::tuple<std::string, int, int>
 *         {final status string, recompute count after first update, recompute count after second update}
 */
std::tuple<std::string, int, int> test_filter_trigger(double initialValue,
                                                      double firstUpdate,
                                                      double secondUpdate,
                                                      double diffThreshold,
                                                      double levelThreshold) {
    using namespace reaction;

    // 1. Create a reactive variable for the sensor using reaction::var with initial value
    auto sensor = var(initialValue);

    // 2. Create two reactive variables to track recompute count and last processed value using reaction::var
    auto recomputeCount = var(0);
    auto lastProcessedValue = var(initialValue);

    // 3. Create a filter-triggered calculation using reaction::calc that:
    //    - Compares current value with last processed value to check if difference exceeds threshold
    //    - If threshold is exceeded, updates the recompute count and last processed value
    //    - Returns a status string indicating "HIGH" or "NORMAL" based on levelThreshold
    auto statusCalc = calc([&]() -> std::string {
        double currentValue = sensor.get();
        double lastValue = lastProcessedValue.get();

        // Check if difference exceeds threshold
        bool trigger = std::abs(currentValue - lastValue) >= diffThreshold;

        if (trigger) {
            // Update recompute count and last processed value
            recomputeCount.value(recomputeCount.get() + 1);
            lastProcessedValue.value(currentValue);

            // Determine status based on levelThreshold
            if (currentValue >= levelThreshold) {
                return "HIGH";
            } else {
                return "NORMAL";
            }
        }

        // If no trigger, return previous status without updating counts
        return lastProcessedValue.get() >= levelThreshold ? "HIGH" : "NORMAL";
    });

    // 4. Apply a filter to the calculation using the filter method with a lambda that implements the threshold logic
    statusCalc.filter([&](const std::string& status) -> bool {
        double currentValue = sensor.get();
        double lastValue = lastProcessedValue.get();
        return std::abs(currentValue - lastValue) >= diffThreshold;
    });

    // 5. Update the sensor variable with the first value using the value method
    sensor.value(firstUpdate);

    // 6. Use get() to retrieve the recompute count after first update
    int firstCount = recomputeCount.get();

    // 7. Update the sensor variable with the second value using the value method
    sensor.value(secondUpdate);

    // 8. Use get() to retrieve the recompute count after second update
    int secondCount = recomputeCount.get();

    // 9. Use get() to get the final status string
    std::string finalStatus = statusCalc.get();

    // 10. Return a tuple containing the final status, first recompute count, and second recompute count
    return std::make_tuple(finalStatus, firstCount, secondCount);
}

}  // namespace test_reaction
```

## Key Implementation Details:

1. **Reactive Variable Creation**: Used `reaction::var` to create the sensor variable and tracking variables as specified.

2. **Filter-Triggered Calculation**: Implemented the calculation logic that:
   - Compares current and last processed values
   - Updates recompute count only when threshold is exceeded
   - Returns appropriate status based on level threshold

3. **Filter Application**: Applied the filter using the `filter` method with a lambda that encapsulates the threshold logic.

4. **Value Updates**: Used the `value` method to update the sensor variable with both test values.

5. **Reactive Behavior**: Leveraged the reactive nature of the framework where changes automatically propagate through the dependency graph.

6. **Thread Safety**: The implementation respects the thread registration requirements through the `REACTION_REGISTER_THREAD` macro used internally by the reaction functions.

This implementation demonstrates proper usage of the reaction framework's reactive programming patterns while meeting all the specified assessment objectives.

