    bool sharedLockNoSafety = mutex.try_shared_lock_no_safety();
    // 5. Record result
    SharedMutexResult result{
        .trySharedWithoutSafety = sharedLockNoSafety,
        .tryUniqueWhileSharedWithoutSafety = false,
        .trySharedWithSafety = false,
        .tryUniqueWhileSharedWithSafety = false
    };

    // 6. Unlock shared lock if acquired
