        mutex.unlock_shared();
    }

    // 7. Create ConditionalSharedLockGuard in a scope block
    {
        reaction::ConditionalSharedLockGuard<reaction::ConditionalSharedMutex> guard(mutex);

        // 8. Attempt to acquire unique lock while shared lock is held without safety
        bool uniqueLockNoSafety = mutex.try_unique_lock_no_safety();
        // 9. Record result
        result.tryUniqueWhileSharedWithoutSafety = uniqueLockNoSafety;

        // 10. Unlock unique lock if acquired
        if (uniqueLockNoSafety) {
            mutex.unlock();
        }
    } // 11. Exit guard scope (RAII automatically unlocks)

    // 12. Enable thread safety
